def build_safe_prompt(user_data):
    # INC-2025-11-02-B Fix: Force token evaluation and strict escapement
    safe_content = TokenSanitizer.limit_and_escape(user_data.raw_text, max_tokens=16384)

    prompt = ChatPromptTemplate.from_messages([
        ("system", "Analyze the following data payload."),
        ("user", "{content}")
    ])
    return prompt.format_messages(content=safe_content)

